  // Filter out unauthorized errors from display - utility function
  const getDisplayableError = (error: string | null) => {
    if (!error) return null;
    const lowerError = error.toLowerCase();
    if (lowerError.includes('unauthorized') || lowerError.includes('401')) {
      return null;
    }
    return error;
  };

  // Custom setError function that filters out unauthorized errors
  const setDisplayableError = (newError: string | null) => {
    const displayableError = getDisplayableError(newError);
    setError(displayableError);
  };

  // Custom toast error function that filters unauthorized errors
  const showError = (errorMessage: string) => {
    const displayableError = getDisplayableError(errorMessage);
    if (displayableError) {
      toast.error(displayableError);
    }
  };

  // ============================================================
  // AI MODEL REGISTRY — Central config. Update model names here
  // as providers release new versions.
