  const auroraWave1Ref = useRef<SVGPathElement>(null);
  const auroraWave2Ref = useRef<SVGPathElement>(null);

  // Gradually transition animation speed over 3.5 seconds using Web Animations API
  useEffect(() => {
    const wave1 = auroraWave1Ref.current;
    const wave2 = auroraWave2Ref.current;

    if (!wave1 || !wave2) return;

    // Get the CSS animations
    const animations1 = wave1.getAnimations();
    const animations2 = wave2.getAnimations();

    if (animations1.length === 0 || animations2.length === 0) return;

    const anim1 = animations1[0];
    const anim2 = animations2[0];

    // Target playback rates: slower duration = slower rate
    // Base durations: 60s and 70s
    // Fast durations: 17s and 20s
    // PlaybackRate = baseDuration / targetDuration
    const targetRate1 = indicatorIsOnline ? 60 / 17 : 1; // ~3.53x or 1x
    const targetRate2 = indicatorIsOnline ? 70 / 20 : 1; // ~3.5x or 1x

    const startRate1 = anim1.playbackRate;
    const startRate2 = anim2.playbackRate;

    const startTime = performance.now();
    const transitionDuration = 3500; // 3.5 seconds

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / transitionDuration, 1);

      // Smooth easing curve
      const easedProgress = progress < 0.5
        ? 4 * progress * progress * progress
        : 1 - Math.pow(-2 * progress + 2, 3) / 2;

      const newRate1 = startRate1 + (targetRate1 - startRate1) * easedProgress;
      const newRate2 = startRate2 + (targetRate2 - startRate2) * easedProgress;

      anim1.playbackRate = newRate1;
      anim2.playbackRate = newRate2;

      if (progress < 1) {
        requestAnimationFrame(animate);
      }
    };

    requestAnimationFrame(animate);
  }, [indicatorIsOnline]);

