  // Handle file attachment
  const handleFileAttach = (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    // Calculate how many more images we can add
    const remainingSlots = 9 - attachedImages.length;
    if (remainingSlots === 0) {
      // Show error in placeholder for 3 seconds
      setShowImageLimitError(true);
      setTimeout(() => {
        setShowImageLimitError(false);
      }, 3000);
      return;
    }

    // Process files (up to remaining slots)
    const filesToProcess = Array.from(files).slice(0, remainingSlots);
    const newImages: Array<{ url: string; name: string; type: string }> = [];

    for (const file of filesToProcess) {
      // Check if it's an image or PDF
      if (!file.type.startsWith('image/') && file.type !== 'application/pdf') {
        toast.error('Only image and PDF files are supported', {
          description: `${file.name} is not a supported file type.`,
          duration: 3000,
        });
        continue;
      }

      // Check file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        toast.error('File too large', {
          description: `${file.name} is larger than 5MB.`,
          duration: 3000,
        });
        continue;
      }

      // Create object URL for preview
      const url = URL.createObjectURL(file);
      newImages.push({ url, name: file.name, type: file.type });
    }

    // Add new images to state
    if (newImages.length > 0) {
      setAttachedImages(prev => [...prev, ...newImages]);

      if (newImages.length < filesToProcess.length) {
        toast.info('Some files were skipped', {
          description: 'Invalid or oversized files were not added.',
          duration: 3000,
        });
      }
    }

    // Clear the file input so the same files can be selected again
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  // Remove attached image by index
  const removeAttachedImage = (index: number) => {
    const imageToRemove = attachedImages[index];
    if (imageToRemove) {
      URL.revokeObjectURL(imageToRemove.url);
      setAttachedImages(prev => prev.filter((_, i) => i !== index));
    }
  };

