  // Helper function to calculate time in a timezone using actual timezone identifier
  const getTimeForTimezone = (offset: number, timezoneId?: string): string => {
    try {
      // Use the timezone identifier if available for accurate time (handles DST automatically)
      if (timezoneId) {
        const formatter = new Intl.DateTimeFormat('en-US', {
          timeZone: timezoneId,
          hour: '2-digit',
          minute: '2-digit',
          hour12: false
        });
        return formatter.format(currentTime);
      }
    } catch (e) {
      // Fallback to offset calculation if timezone identifier is invalid
    }

    // Fallback: Calculate using UTC offset
    const now = new Date(currentTime);
    const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
    const tzTime = new Date(utc + (3600000 * offset));
    const hours = tzTime.getHours().toString().padStart(2, '0');
    const minutes = tzTime.getMinutes().toString().padStart(2, '0');
    return `${hours}:${minutes}`;
  };



