  // Optimized image protection - Run only once
  useEffect(() => {
    const protectAllImages = () => {
      const images = document.querySelectorAll('img');
      images.forEach(img => {
        if (!img.hasAttribute('data-protected')) {
          img.draggable = false;
          img.setAttribute('draggable', 'false');
          img.setAttribute('data-protected', 'true');

          const preventActions = (e: Event) => {
            e.preventDefault();
            e.stopPropagation();
            return false;
          };

          img.addEventListener('contextmenu', preventActions, { passive: false });
          img.addEventListener('dragstart', preventActions, { passive: false });
          img.addEventListener('mousedown', (e) => {
            if (e.button === 0) {
              e.preventDefault();
              e.stopPropagation();
            }
            return false;
          }, { passive: false });
        }
      });
    };

    // Run protection once immediately
    protectAllImages();

    // Set up optimized observer for new images only
    const observer = new MutationObserver((mutations) => {
      let hasNewImages = false;
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (node.nodeType === 1) {
            const element = node as Element;
            if (element.tagName === 'IMG' || element.querySelectorAll('img').length > 0) {
              hasNewImages = true;
            }
          }
        });
      });

      if (hasNewImages) {
        protectAllImages();
      }
    });

    observer.observe(document.body, {
      childList: true,
      subtree: true
    });

    return () => {
      observer.disconnect();
    };
  }, []);

