  // Normalizer to convert old standard time to military time
  const convertToMilitary = (timeStr: string) => {
    if (!timeStr) return '';
    const match = timeStr.match(/(\d+):(\d+)\s*(AM|PM)/i);
    if (!match) return timeStr;
    let h = parseInt(match[1], 10);
    const m = match[2];
    const mod = match[3].toUpperCase();
    if (mod === 'PM' && h < 12) h += 12;
    if (mod === 'AM' && h === 12) h = 0;
    return `${h.toString().padStart(2, '0')}:${m}`;
  };

  const normalizeHours = (hoursObj: any) => {
    if (!hoursObj || typeof hoursObj !== 'object') return hoursObj;
    const normalized = { ...hoursObj };
    Object.keys(normalized).forEach(day => {
      if (normalized[day] && typeof normalized[day] === 'object') {
        normalized[day] = {
          ...normalized[day],
          start: convertToMilitary(normalized[day].start),
          end: convertToMilitary(normalized[day].end)
        };
      }
    });
    return normalized;
  };

