  const handleBusinessSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Determine which business value to use
    const businessToSubmit = showCustomBusiness ? customBusiness : lineOfBusiness;

    if (!businessToSubmit.trim()) return;
    if (isAnimating) return;

    // Check token with recovery attempt
    let currentToken = accessToken;
    if (!currentToken) {
      console.log('No access token in handleBusinessSubmit, attempting refresh...');
      try {
        const { data } = await supabase.auth.getSession();
        currentToken = data.session?.access_token || null;
        if (currentToken) {
          setAccessToken(currentToken);
        }
      } catch (e) {
        console.warn('Session refresh failed', e);
      }
    }

    setIsLoading(true);
    setError(null);
    setIsAnimating(true);

    const companyData = {
      companyName: companyName.trim(),
      lineOfBusiness: businessToSubmit.trim()
    };

    // Always save locally first - wrapped in try/catch
    try {
      const userData = offlineStorage.getUserData() || {};
      userData.companyName = companyName.trim();
      userData.lineOfBusiness = businessToSubmit.trim();

      // Also save website if available from previous step
      if (websiteData?.url) {
        setProfileWebsite(websiteData.url);
        userData.profileWebsite = websiteData.url;
      }

      offlineStorage.saveUserData(userData);
    } catch (storageError) {
      console.warn('Local storage save failed:', storageError);
    }

    // Update the lineOfBusiness state with the actual saved value
    setLineOfBusiness(businessToSubmit.trim());
    saveBusinessContext({ companyName: companyName.trim(), lineOfBusiness: businessToSubmit.trim() });

    // Auto-fill profile fields from onboarding data
    if (companyName.trim()) setBusinessName(companyName.trim());
    if (websiteData?.url) setWebsite(websiteData.url);

    if (!serverAvailable || !isOnline || !currentToken) {
      console.log('Server unavailable or no token - company info saved locally and added to sync queue');
      offlineStorage.addToSyncQueue('save-company', companyData);

      // Queue website update if available
      if (websiteData?.url) {
        const profileData = {
          name: userName.trim(),
          phone: profilePhone.trim(), // Use current state or empty string
          website: websiteData.url
        };
        offlineStorage.addToSyncQueue('save-profile', profileData);
      }

      setSyncQueue(offlineStorage.getSyncQueue());

      const timer1 = setTimeout(() => {
        if (mountedRef.current) {
          setCurrentStep('welcome');
          setIsAnimating(false);

          const timer2 = setTimeout(() => {
            if (mountedRef.current) {
              setCurrentStep('dashboard');
            }
          }, 4000);
          activeTimeouts.current.push(timer2);
        }
      }, 50);
      activeTimeouts.current.push(timer1);
      setIsLoading(false);
      return;
    }

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 10000);

      // 1. Save company info
      const companyPromise = fetch(`https://${projectId}.supabase.co/functions/v1/make-server-3f7de5a4/auth/save-company`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${currentToken}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(companyData),
        signal: controller.signal,
      });

      // 2. Save profile (website) if available
      let profilePromise = Promise.resolve(new Response(JSON.stringify({ success: true })));
      if (websiteData?.url) {
        const profileData = {
          name: userName.trim(),
          phone: profilePhone.trim(),
          website: websiteData.url
        };

        profilePromise = fetch(`https://${projectId}.supabase.co/functions/v1/make-server-3f7de5a4/auth/save-profile`, {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${currentToken}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(profileData),
          signal: controller.signal,
        });
      }

      // Execute both requests
      const [companyResponse, profileResponse] = await Promise.all([companyPromise, profilePromise]);

      clearTimeout(timeoutId);

      if (!companyResponse.ok) {
        const errorData = await companyResponse.json();
        throw new Error(errorData.error || 'Failed to save company information');
      }

      if (websiteData?.url && !profileResponse.ok) {
        console.warn('Failed to save website to profile, but continuing');
      }

      console.log('Company and profile information saved successfully');

      // Mark welcome as seen for first-time users (they'll get the full experience once)
      if (isFirstTimeUser && currentToken) {
        await markWelcomeSeen(currentToken);
      }

      const timer1 = setTimeout(() => {
        if (mountedRef.current) {
          // Check if user had an intended destination after completing onboarding
          if (intendedDestination && (intendedDestination === 'whatsapp' || intendedDestination === 'analytics')) {
            console.log(`User completed onboarding successfully, going to intended destination: ${intendedDestination}`);
            setCurrentStep(intendedDestination);
            setIntendedDestination(null); // Clear the intended destination
          } else {
            console.log('User completed onboarding successfully, going to welcome screen');
            setCurrentStep('welcome');
            // Auto-transition is now handled by the welcome screen itself
          }
          setIsAnimating(false);
        }
      }, 50);
      activeTimeouts.current.push(timer1);
    } catch (error: any) {
      console.log('Company save error:', error.message);

      if (error.name === 'AbortError' || error.message.includes('fetch') || error.message.includes('Failed to fetch')) {
        console.log('Network error - company info saved locally and added to sync queue');
        setServerAvailable(false);
        offlineStorage.addToSyncQueue('save-company', companyData);
        setSyncQueue(offlineStorage.getSyncQueue());

        const timer1 = setTimeout(() => {
          if (mountedRef.current) {
            // Check if user had an intended destination after completing onboarding
            if (intendedDestination && (intendedDestination === 'whatsapp' || intendedDestination === 'analytics')) {
              console.log(`User completed onboarding, going to intended destination: ${intendedDestination}`);
              setCurrentStep(intendedDestination);
              setIntendedDestination(null); // Clear the intended destination
            } else {
              console.log('User completed onboarding, going to welcome screen');
              setCurrentStep('welcome');
              // Auto-transition is now handled by the welcome screen itself
            }
            setIsAnimating(false);
          }
        }, 50);
        activeTimeouts.current.push(timer1);
      } else {
        setError(error.message || 'Failed to save company information');
        setIsAnimating(false);
      }
    } finally {
      setIsLoading(false);
    }
  };

