  // Track previous customer chat for detecting chat changes vs message updates
  const prevSelectedCustomerChatRef = React.useRef<string | null>(null);
  const prevMessageCountRef = React.useRef<number>(0);

  // Auto-scroll to bottom when messages change (WhatsApp-style behavior)
  // Using useLayoutEffect to scroll BEFORE browser paint (prevents visual glitch)
  React.useLayoutEffect(() => {
    if (customerChatMessagesRef.current && selectedCustomerChat && showCustomerChats) {
      const currentCustomer = mockCustomerChats.find(c => c.id === selectedCustomerChat);
      const currentMessageCount = currentCustomer?.messages.length || 0;

      // Check if this is a new chat selection (instant scroll) or new message (smooth scroll)
      const isChatChange = prevSelectedCustomerChatRef.current !== selectedCustomerChat;
      const isNewMessage = currentMessageCount > prevMessageCountRef.current;

      if (isChatChange) {
        // For chat changes, scroll instantly BEFORE paint to avoid visual glitch
        // Use a single requestAnimationFrame to ensure DOM is ready
        requestAnimationFrame(() => {
          if (customerChatMessagesRef.current) {
            customerChatMessagesRef.current.scrollTop = customerChatMessagesRef.current.scrollHeight;
          }
        });
      } else if (isNewMessage) {
        // For new messages, use smooth scroll
        requestAnimationFrame(() => {
          if (customerChatMessagesRef.current) {
            customerChatMessagesRef.current.scrollTo({
              top: customerChatMessagesRef.current.scrollHeight,
              behavior: 'smooth'
            });
          }
        });
      }

      // Update refs
      prevSelectedCustomerChatRef.current = selectedCustomerChat;
      prevMessageCountRef.current = currentMessageCount;
    }
  }, [selectedCustomerChat, mockCustomerChats, showCustomerChats]);

  // Reset scroll tracking when leaving manual mode to ensure fresh scroll-to-bottom on return
  useEffect(() => {
    if (whatsappMode !== 'manual') {
      prevSelectedCustomerChatRef.current = null;
      prevMessageCountRef.current = 0;
    }
  }, [whatsappMode]);

  // Reset scroll tracking when modal closes to ensure fresh scroll-to-bottom on reopen
  useEffect(() => {
    if (!showCustomerChats) {
      prevSelectedCustomerChatRef.current = null;
      prevMessageCountRef.current = 0;
    }
  }, [showCustomerChats]);

  // Reset scroll tracking when entering selection, block/remove, or file send mode to ensure fresh scroll-to-bottom
  useEffect(() => {
    if (isSelectionMode || isBlockRemoveMode || isFileSendMode) {
      prevSelectedCustomerChatRef.current = null;
      prevMessageCountRef.current = 0;
    }
  }, [isSelectionMode, isBlockRemoveMode, isFileSendMode]);

  // Handle escape key to exit file send mode
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isFileSendMode) {
        setIsFileSendMode(false);
        setSelectedFiles(new Set());
        setFileSelectionOrder([]);
        setFileSearchQuery('');
        setSelectedFileType('all');
        if (mockCustomerChats.length > 0) {
          setSelectedCustomerChat(mockCustomerChats[0].id);
        }
      }
    };

    if (isFileSendMode) {
      window.addEventListener('keydown', handleEscape);
      return () => window.removeEventListener('keydown', handleEscape);
    }
  }, [isFileSendMode, mockCustomerChats]);

  // Handle quick action card clicks with card-to-chat animation
  const handleQuickActionClick = (action: string, event: React.MouseEvent) => {
    if (animatingButton) return; // Prevent multiple animations

    // Get the clicked card element and chat messages container
    const cardElement = event.currentTarget as HTMLElement;
    const cardRect = cardElement.getBoundingClientRect();
    const chatContainer = chatMessagesRef.current?.getBoundingClientRect();

    if (!chatContainer) return;

    // Map actions to content and icons
    const actionMap = {
      'welcome-message': {
        content: 'Help me create a professional welcome message for my customers',
        icon: <MessageCircle className="w-6 h-6 text-blue-600 dark:text-blue-400" />,
        title: 'Create welcome message',
        description: 'Generate a professional greeting for new customers',
        bgLight: 'bg-blue-100',
        bgDark: 'bg-blue-900'
      },
      'auto-responses': {
        content: 'I want to set up auto responses for common questions',
        icon: <Bot className="w-6 h-6 text-green-600 dark:text-green-400" />,
        title: 'Setup auto responses',
        description: 'Configure intelligent replies for common questions',
        bgLight: 'bg-green-100',
        bgDark: 'bg-green-900'
      },
      'business-hours': {
        content: 'How do I configure my business hours?',
        icon: <Clock className="w-6 h-6 text-purple-600 dark:text-purple-400" />,
        title: 'Set business hours',
        description: 'Define when your AI should be most active',
        bgLight: 'bg-purple-100',
        bgDark: 'bg-purple-900'
      },
      'languages': {
        content: 'I need help setting up multiple languages for my customers',
        icon: <div className="w-6 h-6 text-orange-600 dark:text-orange-400"><LanguageIcon /></div>,
        title: 'Configure languages',
        description: 'Choose which languages your AI should support',
        bgLight: 'bg-orange-100',
        bgDark: 'bg-orange-900'
      }
    };

    const actionData = actionMap[action as keyof typeof actionMap];
    if (!actionData) return;

    // Calculate positions for card animation
    const startPosition = {
      x: cardRect.left + cardRect.width / 2,
      y: cardRect.top + cardRect.height / 2
    };

    // Target position in chat area (right side for user messages)
    const endPosition = {
      x: chatContainer.right - 200, // Position on right side like user messages
      y: chatContainer.bottom - 100  // Near bottom of chat area
    };

    // Start the card shrinking animation
    setAnimatingButton({
      id: action,
      content: actionData.content,
      startPosition,
      endPosition,
      icon: actionData.icon,
      title: actionData.title
    });

    // Hide the original card during animation
    cardElement.style.opacity = '0.3';
    cardElement.style.transform = 'scale(0.95)';
    cardElement.style.transition = 'opacity 0.3s ease, transform 0.3s ease';

    // Complete the animation and add card as chat message
    setTimeout(() => {
      // Create a user message with the card content
      const cardMessage = {
        id: Date.now().toString(),
        type: 'user' as const,
        content: actionData.title, // Use the card title as the message
        timestamp: new Date(),
        isCard: true, // Special flag to render as card
        cardData: {
          icon: actionData.icon,
          title: actionData.title,
          description: actionData.description,
          bgLight: actionData.bgLight,
          bgDark: actionData.bgDark
        }
      };

      // Add the card message to chat (keep welcome cards visible)
      setChatMessages(prev => [...prev, cardMessage]);
      setChatInput('');
      setHasSuggestion(false);
      setCurrentSuggestion('');
      setAnimatingButton(null);
      setIsAiTyping(true);

      // Restore card appearance
      cardElement.style.opacity = '1';
      cardElement.style.transform = 'scale(1)';
      cardElement.style.transition = '';

      // Auto-scroll to show the new message
      setTimeout(() => scrollToBottom(), 50);

      // Generate AI response specific to the card using new format
      setTimeout(async () => {
        setIsAiTyping(false);
        await generateAiResponse(actionData.content);
      }, 1500 + Math.random() * 1000); // Random delay between 1.5-2.5 seconds

    }, 800); // Animation duration
  };

