  // Check if a feature is accessible based on user tier - UPDATED: All WhatsApp features are now accessible to all tiers
  const isFeatureAccessible = (feature: string) => {
    // WhatsApp features - now accessible to ALL tiers
    const whatsappFeatures = ['main-options', 'select-languages', 'booking-directory', 'configure-hours', 'holiday-days', 'set-reminders', 'google-calendar', 'outlook-calendar', 'google-reviews', 'edit-template', 'edit-staff', 'follow-ups', 'payment-links', 'white-label'];

    if (whatsappFeatures.includes(feature)) return true; // All WhatsApp features are accessible to all tiers

    // Keep existing restrictions for non-WhatsApp features (analytics, other platforms)
    const basicFeatures = ['main-options', 'select-languages', 'booking-directory', 'configure-hours', 'holiday-days'];
    const proFeatures = ['set-reminders', 'google-calendar', 'outlook-calendar', 'google-reviews'];
    const premiumFeatures = ['edit-template', 'edit-staff', 'follow-ups', 'payment-links'];
    const enterpriseFeatures = ['white-label'];

    if (basicFeatures.includes(feature)) return true;
    if (userTier === 'basic') return false;

    if (proFeatures.includes(feature)) return userTier !== 'basic';
    if (userTier === 'pro') return !premiumFeatures.includes(feature) && !enterpriseFeatures.includes(feature);

    if (premiumFeatures.includes(feature)) return ['premium', 'enterprise'].includes(userTier);
    if (userTier === 'premium') return !enterpriseFeatures.includes(feature);

    if (enterpriseFeatures.includes(feature)) return userTier === 'enterprise';

    return true;
  };

  // Get required tier for a feature
  const getRequiredTier = (feature: string) => {
    const proFeatures = ['set-reminders', 'google-calendar', 'outlook-calendar', 'google-reviews'];
    const premiumFeatures = ['edit-template', 'edit-staff', 'follow-ups', 'payment-links', 'analytics'];
    const enterpriseFeatures = ['white-label'];

    if (proFeatures.includes(feature)) return 'pro';
    if (premiumFeatures.includes(feature)) return 'premium';
    if (enterpriseFeatures.includes(feature)) return 'enterprise';
    return 'basic';
  };

